#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string removeKdigits(string num, int k) {
        string stack;
        for (char n : num) {
            while (k && !stack.empty() && stack.back() > n) {
                stack.pop_back();
                k--;
            }
            stack.push_back(n);
        }
        while (k--) {
            stack.pop_back();
        }
        int start = 0;
        while (start < stack.size() && stack[start] == '0') {
            start++;
        }
        return start == stack.size() ? "0" : stack.substr(start);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string num;
    if (!(cin >> num)) return 0;
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    string ans = sol.removeKdigits(num, k);
    cout << ans << "\n";
    return 0;
}
